7768	    return m && m->max_entries > 0 ? m->max_entries : DS4_TOOL_MEMORY_DEFAULT_MAX_IDS;
7769	}
7770	
7771	static size_t tool_memory_max_bytes(const tool_memory *m) {
7772	    return m && m->max_bytes > 0 ? m->max_bytes : DS4_TOOL_MEMORY_MAX_BYTES;
7773	}
