8542	static void kv_cache_restore_tool_memory_for_messages(server *s, const chat_msgs *msgs) {
8543	    if (!s || s->disable_exact_dsml_tool_replay || !s->kv.enabled || !msgs) return;
8544	    stop_list wanted = {0};
8545	    collect_tool_call_ids(msgs, &wanted);
8546	    if (wanted.len == 0) return;
8547	    /* Tool replay payloads are stored next to KV checkpoints; keep them model
8548	     * scoped too, since token positions and graph state are not portable across
8549	     * Flash/Pro shapes even when the rendered chat text is identical. */
8550	    uint8_t model_id = s->engine ? (uint8_t)ds4_engine_model_id(s->engine) : 0;
8551	
8552	    DIR *d = opendir(s->kv.dir);
8553	    if (!d) {
8554	        id_list_free(&wanted);
8555	        return;
8556	    }
8557	    struct dirent *de;
8558	    while ((de = readdir(d)) != NULL) {
8559	        char sha[41];
8560	        if (!sha_hex_name(de->d_name, sha)) continue;
